import{_ as t}from"./chunks/smart-scaffold.Cj8WJJfv.js";import{_ as o,o as l,c as i,ag as n}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"Smart Scaffold 智能中间件集成验证脚手架","description":"","frontmatter":{},"headers":[{"level":1,"title":"Smart Scaffold 智能中间件集成验证脚手架","slug":"smart-scaffold-智能中间件集成验证脚手架","link":"#smart-scaffold-智能中间件集成验证脚手架","children":[{"level":2,"title":"项目简介","slug":"项目简介","link":"#项目简介","children":[]},{"level":2,"title":"版本选择","slug":"版本选择","link":"#版本选择","children":[{"level":3,"title":"Spring Boot 版本","slug":"spring-boot-版本","link":"#spring-boot-版本","children":[]},{"level":3,"title":"Dubbo 版本","slug":"dubbo-版本","link":"#dubbo-版本","children":[]},{"level":3,"title":"Spring Cloud 版本","slug":"spring-cloud-版本","link":"#spring-cloud-版本","children":[]}]},{"level":2,"title":"版本对比","slug":"版本对比","link":"#版本对比","children":[]},{"level":2,"title":"核心功能","slug":"核心功能","link":"#核心功能","children":[]},{"level":2,"title":"技术支持","slug":"技术支持","link":"#技术支持","children":[]},{"level":2,"title":"快速开始","slug":"快速开始","link":"#快速开始","children":[]},{"level":2,"title":"注意事项","slug":"注意事项","link":"#注意事项","children":[]}]}],"relativePath":"dev/smart-scaffold/index.md","filePath":"dev/smart-scaffold/index.md"}'),a={name:"dev/smart-scaffold/index.md"};function s(e,r,d,g,h,c){return l(),i("div",null,[...r[0]||(r[0]=[n('<h1 id="smart-scaffold-智能中间件集成验证脚手架" tabindex="-1">Smart Scaffold 智能中间件集成验证脚手架 <a class="header-anchor" href="#smart-scaffold-智能中间件集成验证脚手架" aria-label="Permalink to &quot;Smart Scaffold 智能中间件集成验证脚手架&quot;">​</a></h1><h2 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h2><p>智能中间件集成验证脚手架是面向开发者打造的一站式微服务项目脚手架，深度融合 AI 能力与主流中间件集成方案，支持开发者快速完成各类常用中间件服务的集成、验证与测试，大幅提升开发效率。</p><p>本项目提供标准化中间件集成方案、统一 Web 界面及配套测试工具，同时集成智能辅助能力，支持 Ollama 本地模型与 OpenAI API 调用。开发者可借助该脚手架快速搭建测试环境、验证中间件功能，并通过 AI 能力加速开发流程，有效缩短项目研发与调试周期。</p><h2 id="版本选择" tabindex="-1">版本选择 <a class="header-anchor" href="#版本选择" aria-label="Permalink to &quot;版本选择&quot;">​</a></h2><p>根据您的技术栈和需求，选择适合的智能中间件集成验证脚手架版本：</p><h3 id="spring-boot-版本" tabindex="-1">Spring Boot 版本 <a class="header-anchor" href="#spring-boot-版本" aria-label="Permalink to &quot;Spring Boot 版本&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：17+</li><li><strong>Spring Boot 版本</strong>：3.5.12</li><li><strong>架构模式</strong>：单体分层架构</li><li><strong>模块结构</strong>：4 个子模块（common / dao / service / web）</li><li><strong>主要特性</strong>：提供完整的中间件集成与 AI 能力，适合快速开发和测试</li><li><strong>界面预览</strong>：</li></ul><p><img src="'+t+'" alt="智能中间件集成验证脚手架界面"></p><ul><li><strong>文档链接</strong>：<a href="./smart-scaffold-springboot.html">Spring Boot 版本</a></li></ul><h3 id="dubbo-版本" tabindex="-1">Dubbo 版本 <a class="header-anchor" href="#dubbo-版本" aria-label="Permalink to &quot;Dubbo 版本&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：17+</li><li><strong>Spring Boot 版本</strong>：3.5.12</li><li><strong>Dubbo 版本</strong>：3.2.0</li><li><strong>注册中心</strong>：Zookeeper 3.5+</li><li><strong>架构模式</strong>：分布式 RPC 架构</li><li><strong>模块结构</strong>：3 个子模块（api / provider / consumer）</li><li><strong>主要特性</strong>：基于 Dubbo 微服务框架，适合分布式服务架构场景</li><li><strong>界面预览</strong>：</li></ul><p><img src="'+t+'" alt="智能中间件集成验证脚手架界面"></p><ul><li><strong>文档链接</strong>：<a href="./smart-scaffold-dubbo.html">Dubbo 版本</a></li></ul><h3 id="spring-cloud-版本" tabindex="-1">Spring Cloud 版本 <a class="header-anchor" href="#spring-cloud-版本" aria-label="Permalink to &quot;Spring Cloud 版本&quot;">​</a></h3><ul><li><strong>JDK 版本</strong>：17+</li><li><strong>Spring Boot 版本</strong>：3.5.12</li><li><strong>Spring Cloud 版本</strong>：2025.0.0</li><li><strong>注册中心</strong>：Zookeeper 3.5+</li><li><strong>架构模式</strong>：微服务架构</li><li><strong>模块结构</strong>：3 个子模块（common / provider / consumer）</li><li><strong>主要特性</strong>：基于 Spring Cloud 生态，适合云原生微服务架构场景</li><li><strong>界面预览</strong>：</li></ul><p><img src="'+t+'" alt="智能中间件集成验证脚手架界面"></p><ul><li><strong>文档链接</strong>：<a href="./smart-scaffold-springcloud.html">Spring Cloud 版本</a></li></ul><h2 id="版本对比" tabindex="-1">版本对比 <a class="header-anchor" href="#版本对比" aria-label="Permalink to &quot;版本对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>对比项</th><th>Spring Boot 版</th><th>Dubbo 版</th><th>Spring Cloud 版</th></tr></thead><tbody><tr><td><strong>架构模式</strong></td><td>单体分层架构</td><td>分布式 RPC 架构</td><td>微服务架构</td></tr><tr><td><strong>Spring Boot</strong></td><td>3.5.12</td><td>3.5.12</td><td>3.5.12</td></tr><tr><td><strong>额外框架</strong></td><td>—</td><td>Dubbo 3.2.0</td><td>Spring Cloud 2025.0.0</td></tr><tr><td><strong>注册中心</strong></td><td>无</td><td>Zookeeper 3.5+</td><td>Zookeeper 3.5+</td></tr><tr><td><strong>模块数</strong></td><td>4 个</td><td>3 个</td><td>3 个</td></tr><tr><td><strong>服务通信</strong></td><td>进程内调用</td><td>Dubbo RPC</td><td>OpenFeign HTTP</td></tr><tr><td><strong>前端框架</strong></td><td>LayUI 2.13.5</td><td>LayUI 2.13.5</td><td>LayUI 2.13.5</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><p><strong>Smart-Scaffold 智能中间件集成验证脚手架</strong></p><p><strong>核心开发功能：</strong></p><p>专为企业级中间件与 AI 能力集成深度打造，一站式重构多组件验证流程，开箱即用、零代码快速验证全链路功能，完美支撑开发、测试、生产多环境部署需求，解决多中间件分散调试、AI 能力接入复杂等核心痛点。</p><ul><li><strong>01：全场景 AI 能力集成</strong> — 无缝对接 Ollama 本地大模型、OpenAI 官方 API，全面支持普通对话交互、SSE 流式实时聊天、SSE 流式文章创作、Chroma 文本向量嵌入等多元化 AI 应用场景，满足本地化与云端 AI 双重使用需求。</li><li><strong>02：全品类中间件集成验证</strong> — 一站式集成主流技术组件，原生支持 MyBatis、Elasticsearch、Kafka、MongoDB、RabbitMQ、Redis、RocketMQ、LDAP 基础操作组件，全覆盖消息队列、搜索引擎、缓存、文档库、身份协议、LDAP目录服务等中间件，快速完成接入调试、功能测试与可用性验证。</li><li><strong>03：标准化身份认证集成</strong> — 深度集成 OAuth2.0、OIDC客户端，适配统一认证中心（CAS），兼容主流企业级单点登录规范；同时内置无认证调试模式，兼顾正式环境安全授权与开发阶段快速调试。</li><li><strong>04：灵活化多数据源管理</strong> — 内置多数据源动态配置机制，可同时对接、切换、操作多个 MySQL 数据库，适配分库业务、多库并行开发等复杂数据场景。</li><li><strong>05：轻量化可视化 Web 操作界面</strong> — 基于 LayUI 搭建一体化可视化界面，零代码门槛，可视化操作即可完成各类中间件功能调试、AI 能力在线演示，大幅降低上手成本。</li><li><strong>06：全覆盖内置测试用例</strong> — 预设各类中间件、AI 模块标准化测试用例，一键执行检测，快速校验服务连通性、接口可用性与功能完整性。</li><li><strong>07：多环境无缝适配</strong> — 独立隔离开发、测试、生产多套环境配置，支持配置快速切换，完美适配本地开发、内网测试、线上部署等不同落地场景。</li><li><strong>08：容器化 / 自动化部署</strong> — 内置标准化 DockerFile 与 Jenkins 部署脚本，一键完成容器打包、自动化部署，无缝接入企业 CI / CD 持续集成流程。</li></ul><h2 id="技术支持" tabindex="-1">技术支持 <a class="header-anchor" href="#技术支持" aria-label="Permalink to &quot;技术支持&quot;">​</a></h2><ul><li><strong>技术支持</strong>：北京必码科技工作室</li><li><strong>官方文档</strong>：<a href="https://bima.cc" target="_blank" rel="noreferrer">https://bima.cc</a></li><li><strong>官方店铺</strong>：<a href="https://bima.taobao.com" target="_blank" rel="noreferrer">https://bima.taobao.com</a></li><li><strong>联系邮箱</strong>：<a href="mailto:bima.cc@qq.com" target="_blank" rel="noreferrer">bima.cc@qq.com</a></li><li><strong>联系微信</strong>：e18929958</li></ul><h2 id="快速开始" tabindex="-1">快速开始 <a class="header-anchor" href="#快速开始" aria-label="Permalink to &quot;快速开始&quot;">​</a></h2><ol><li><strong>选择版本</strong>：根据您的技术栈和需求选择合适的智能中间件集成验证脚手架版本</li><li><strong>查看文档</strong>：点击上方对应版本的链接查看详细文档</li><li><strong>环境准备</strong>：按照文档要求准备 JDK、MySQL 等环境</li><li><strong>配置修改</strong>：根据您的环境修改中间件连接等配置</li><li><strong>构建运行</strong>：使用 Maven 构建并运行项目</li><li><strong>访问服务</strong>：通过 <code>http://localhost:8080</code> 访问脚手架服务</li></ol><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li><strong>环境要求</strong>：确保所有依赖的中间件服务都已正确安装和配置</li><li><strong>网络要求</strong>：构建过程需要访问 Maven 中央仓库，确保网络连接正常</li><li><strong>AI 服务</strong>：使用 AI 功能时需要配置相应的模型服务（Ollama 或 OpenAI API）</li><li><strong>生产环境</strong>：在生产环境中使用前，请进行充分的测试和验证</li></ul>',31)])])}const m=o(a,[["render",s]]);export{p as __pageData,m as default};
